import React from 'react';
import './Home.css';

export default function Home() {
  const handleClick = (action) => {
    alert(`Tu as cliqué sur "${action}"`);
  };

  return (
    <div className="container">
      <header className="header">
        <h1 className="logo">""</h1>
        <nav>
          <button className="btn" onClick={() => handleClick('Connexion')}>Connexion</button>
          <button className="btn" onClick={() => handleClick('Inscription')}>Inscription</button>
          <button className="btn primary" onClick={() => handleClick('Nouvelle Réservation')}>Nouvelle Réservation</button>
        </nav>
      </header>

      <main className="main">
        <h2>Bienvenue sur l'application de réservation</h2>
        <p>Réservez votre salle de réunion en toute simplicité.</p>
      </main>
    </div>
  );
}
import { useNavigate } from 'react-router-dom';

const navigate = useNavigate();

<button className="btn primary" onClick={() => navigate('/reservation')}>
  Nouvelle Réservation
</button>
